      onClick={(e) => e.stopPropagation()}
    >
      <button
        type="button"
        data-testid="pb-ctx-rename"
        style={{
          display: 'block',
          width: '100%',
          textAlign: 'left',
          padding: 'var(--space-1) var(--space-3)',
          fontSize: 'var(--text-sm, 12.5px)',
          color: 'var(--color-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
        onClick={() => {
          onRename();
          onClose();
        }}
      >
        Rename
      </button>
      <button
        type="button"
        data-testid="pb-ctx-duplicate"
        style={{
          display: 'block',
          width: '100%',
          textAlign: 'left',
          padding: 'var(--space-1) var(--space-3)',
          fontSize: 'var(--text-sm, 12.5px)',
          color: 'var(--color-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
        onClick={onDuplicate}
      >
        Duplicate
      </button>
      <button
        type="button"
        data-testid="pb-ctx-delete"
        style={{
          display: 'block',
          width: '100%',
          textAlign: 'left',
          padding: 'var(--space-1) var(--space-3)',
          fontSize: 'var(--text-sm, 12.5px)',
          color: 'var(--color-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
        onClick={onDelete}
      >
        Delete
      </button>
      {onProperties ? (
        <button
          type="button"
          data-testid="pb-ctx-properties"
          style={{
            display: 'block',
            width: '100%',
            textAlign: 'left',
            padding: 'var(--space-1) var(--space-3)',
            fontSize: 'var(--text-sm, 12.5px)',
            color: 'var(--color-foreground)',
            background: 'transparent',
            border: 'none',
            cursor: 'pointer',
          }}
          onClick={onProperties}
        >
          Properties
        </button>
      ) : null}
    </div>
  );
}

