export function WorkspaceLeftRail({
  projectName,
  projectNameRef,
  onProjectNameClick,
  openTabFromElement,
  onSetModeOnly,
  onSemanticCommand,
  onCreateFloorPlan,
  onCreateCeilingPlan,
  onCreate3dView,
  onCreateSectionView,
  onCreateSheet,
  onCreateSchedule,
  onOpenProjectSettings,
  onOpenSavedView,
  onViewDragStart,
  onViewDragEnd,
  activeViewTargetId,
  userDisplayName,
  userId,
  modelId,
  revision,
}: {
  projectName?: string;
  projectNameRef?: RefObject<HTMLButtonElement | null>;
  onProjectNameClick?: () => void;
  openTabFromElement: (el: Element) => void;
  /** Sets mode + viewerMode without touching tab state. Used after
   * `openTabFromElement` has already activated the correct tab, so that
   * `onModeChange` (which calls activateOrOpenKind) doesn't override it. */
  onSetModeOnly?: (mode: WorkspaceMode) => void;
  onSemanticCommand?: (cmd: Record<string, unknown>) => void | Promise<void>;
  onCreateFloorPlan?: () => void;
  /** D1: Create a new Reflected Ceiling Plan view. */
  onCreateCeilingPlan?: () => void;
  onCreate3dView?: () => void;
  onCreateSectionView?: () => void;
  onCreateSheet?: () => void;
  onCreateSchedule?: () => void;
  onOpenProjectSettings?: () => void;
  onOpenSavedView?: (savedViewId: string) => void;
  onViewDragStart?: (elementId: string) => void;
  onViewDragEnd?: () => void;
  activeViewTargetId?: string | null;
  userDisplayName?: string;

export function buildPrimaryNavigationSections(
  elementsById: Record<string, Element>,
): LeftRailSection[] {
  const all = Object.values(elementsById) as Element[];
  const levels = all
    .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
    .sort((a, b) => a.elevationMm - b.elevationMm);
  const allPlanViews = all.filter(
    (e): e is Extract<Element, { kind: 'plan_view' }> => e.kind === 'plan_view',
  );
  const planViews = allPlanViews.filter((p) => p.planViewSubtype !== 'area_plan');
  const viewpoints = all.filter(
    (e): e is Extract<Element, { kind: 'viewpoint' }> => e.kind === 'viewpoint',
  );
  const savedViews = all.filter(
    (e): e is Extract<Element, { kind: 'saved_view' }> => e.kind === 'saved_view',
  );
  const sections = all.filter(
    (e): e is Extract<Element, { kind: 'section_cut' }> => e.kind === 'section_cut',
  );
  const sheets = all.filter((e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet');
  const schedules = all.filter(
    (e): e is Extract<Element, { kind: 'schedule' }> => e.kind === 'schedule',
  );
  const projectSettings = all.find(
    (e): e is Extract<Element, { kind: 'project_settings' }> => e.kind === 'project_settings',
  );
  const levelNameById = new Map(levels.map((l) => [l.id, l.name]));
  return [
    ...(projectSettings
      ? [
          {
            id: 'project',
            label: 'Project',
            icon: ProjectInfoIcon,
            rows: [
              {
                id: projectSettings.id,
                label: 'Project settings',
                icon: ProjectInfoIcon,
                hint: projectSettings.displayLocale ?? 'global settings',
                renamable: false,
              },
            ],
          },
        ]
      : []),
    {
      id: 'floor-plans',
      label: 'Floor Plans',
      icon: PlanViewIcon,
      rows: planViews.map((p) => ({
        id: p.id,
        label: p.name,
        icon: PlanViewIcon,
        hint: `${levelNameById.get(p.levelId) ?? p.levelId}`,
        renamable: true,
      })),
    },
    {
      id: '3d-views',
      label: '3D Views',
      icon: OrbitViewIcon,
      rows: [...viewpoints, ...savedViews]
        .sort((a, b) => a.name.localeCompare(b.name))
        .map((v) => ({
          id: v.id,
          label: v.name,
          icon: OrbitViewIcon,
          hint: v.kind === 'saved_view' ? 'saved 3D snapshot' : 'saved camera',
          renamable: true,
        })),
    },
    {
      id: 'sections',
      label: 'Sections',
      icon: SectionViewIcon,
      rows: sections.map((s) => ({
        id: s.id,
        label: s.name,
        icon: SectionViewIcon,
        hint: 'cut view',
        renamable: true,
      })),
    },
    {
      id: 'sheets',
      label: 'Sheets',
      icon: SheetIcon,
      rows: sheets.map((s) => ({
        id: s.id,
        label: s.name,
        icon: SheetIcon,
        hint: `${sheetIntentLabel(readSheetIntent(s))} · ${s.viewportsMm?.length ?? 0} viewports`,
        renamable: true,
      })),
    },
    {
      id: 'schedules',
      label: 'Schedules',

