function PbContextMenu({
  x,
  y,
  onClose,
  onRename,
  onDuplicate,
  onDelete,
  onProperties,
}: {
  x: number;
  y: number;
  onClose: () => void;
  onRename: () => void;
  onDuplicate: () => void;
  onDelete: () => void;
  /** D7: optional Properties action — shown when provided. */
  onProperties?: () => void;
}): JSX.Element {
  return (
    <div
      data-testid="pb-context-menu"
      style={{
        position: 'fixed',
        top: y,
        left: x,
        zIndex: 9999,
        minWidth: 140,
        background: 'var(--color-surface)',
        border: '1px solid var(--color-border)',
        borderRadius: 'var(--radius-sm, 4px)',
        boxShadow: 'var(--shadow-modal, 0 4px 16px rgba(0,0,0,0.24))',
        padding: 'var(--space-1) 0',
      }}
      onClick={(e) => e.stopPropagation()}
    >
      <button
        type="button"
        data-testid="pb-ctx-rename"
        style={{
          display: 'block',
          width: '100%',
          textAlign: 'left',
          padding: 'var(--space-1) var(--space-3)',
          fontSize: 'var(--text-sm, 12.5px)',
          color: 'var(--color-foreground)',
          background: 'transparent',
          border: 'none',
          cursor: 'pointer',
        }}
        onClick={() => {

          cursor: 'pointer',
        }}
        onClick={onDelete}
      >
        Delete
      </button>
      {onProperties ? (
        <button
          type="button"
          data-testid="pb-ctx-properties"
          style={{
            display: 'block',
            width: '100%',
            textAlign: 'left',
            padding: 'var(--space-1) var(--space-3)',
            fontSize: 'var(--text-sm, 12.5px)',
            color: 'var(--color-foreground)',
            background: 'transparent',
            border: 'none',
            cursor: 'pointer',
          }}
          onClick={onProperties}
        >
          Properties
        </button>
      ) : null}
    </div>
  );
}

